export async function getCategoryList(): Promise<Category[]> {
	const allBlogPosts = await getCollection<"posts">("posts", ({ data }) => {
		return import.meta.env.PROD ? data.draft !== true : true;
	});
	const count: { [key: string]: number } = {};
	allBlogPosts.forEach((post: { data: { category: string | null } }) => {
		if (!post.data.category) {
			const ucKey = i18n(I18nKey.uncategorized);
			count[ucKey] = count[ucKey] ? count[ucKey] + 1 : 1;
			return;
		}

		const categoryName =
			typeof post.data.category === "string"
				? post.data.category.trim()
				: String(post.data.category).trim();

		count[categoryName] = count[categoryName] ? count[categoryName] + 1 : 1;
	});

	const lst = Object.keys(count).sort((a, b) => {
		return a.toLowerCase().localeCompare(b.toLowerCase());
	});

	const ret: Category[] = [];
	for (const c of lst) {
		ret.push({
			name: c,
			count: count[c],
			url: getCategoryUrl(c),
		});
	}
	return ret;
}

export async function getRelatedPosts(originalPost: Post, maxResults: number = 4): Promise<Post[]> {
  const allPosts = await fetchPosts();
  const originalTagsSet = new Set(originalPost.tags ? originalPost.tags.map((tag) => tag.slug) : []);

  const postsWithScores = allPosts.reduce((acc: { post: Post; score: number }[], iteratedPost: Post) => {
    if (iteratedPost.slug === originalPost.slug) return acc;

    let score = 0;
    if (iteratedPost.category && originalPost.category && iteratedPost.category.slug === originalPost.category.slug) {
      score += 5;
    }

    if (iteratedPost.tags) {
      iteratedPost.tags.forEach((tag) => {
        if (originalTagsSet.has(tag.slug)) {
          score += 1;
        }
      });
    }

    acc.push({ post: iteratedPost, score });
    return acc;
  }, []);

  postsWithScores.sort((a, b) => b.score - a.score);

  const selectedPosts: Post[] = [];
  let i = 0;
  while (selectedPosts.length < maxResults && i < postsWithScores.length) {
    selectedPosts.push(postsWithScores[i].post);
    i++;
  }

  return selectedPosts;
}

onMount(async () => {
	let filteredPosts: Post[] = sortedPosts;

	if (tags.length > 0) {
		filteredPosts = filteredPosts.filter(
			(post) =>
				Array.isArray(post.data.tags) &&
				post.data.tags.some((tag) => tags.includes(tag)),
		);
	}

	if (categories.length > 0) {
		filteredPosts = filteredPosts.filter(
			(post) => post.data.category && categories.includes(post.data.category),
		);
	}

	if (uncategorized) {
		filteredPosts = filteredPosts.filter((post) => !post.data.category);
	}

	const grouped = filteredPosts.reduce(
		(acc, post) => {
			const year = post.data.published.getFullYear();
			if (!acc[year]) {
				acc[year] = [];
			}
			acc[year].push(post);
			return acc;
		},
		{} as Record<number, Post[]>,
	);

	const groupedPostsArray = Object.keys(grouped).map((yearStr) => ({
		year: Number.parseInt(yearStr, 10),
		posts: grouped[Number.parseInt(yearStr, 10)],
	}));

	groupedPostsArray.sort((a, b) => b.year - a.year);

	groups = groupedPostsArray;
});

func injectDefineVars(n *astro.Node, values []string) {
	definedVars := "$$definedVars"
	for i, attr := range n.Attr {
		if attr.Key == "style" {
			switch attr.Type {
			case astro.ShorthandAttribute:
				attr.Type = astro.ExpressionAttribute
				attr.Val = fmt.Sprintf("`${%s}; ${%s}`", attr.Key, definedVars)
				n.Attr[i] = attr
				return
			case astro.EmptyAttribute:
				attr.Type = astro.ExpressionAttribute
				attr.Val = definedVars
				n.Attr[i] = attr
				return
			case astro.QuotedAttribute:
				attr.Type = astro.ExpressionAttribute
				attr.Val = fmt.Sprintf("`${\"%s\"}; ${%s}`", attr.Val, definedVars)
				n.Attr[i] = attr
				return
			case astro.TemplateLiteralAttribute:
				attr.Type = astro.ExpressionAttribute
				attr.Val = fmt.Sprintf("`${`%s`}; ${%s}`", attr.Val, definedVars)
				n.Attr[i] = attr
				return
			case astro.ExpressionAttribute:
				attr.Type = astro.ExpressionAttribute
				trimmed := strings.TrimSpace(attr.Val)
				if trimmed[0] == '{' {
					attr.Val = fmt.Sprintf("[%s,%s]", trimmed, definedVars)
				} else {
					attr.Val = fmt.Sprintf("`${%s}; ${%s}`", attr.Val, definedVars)
				}
				n.Attr[i] = attr
				return
			}
		}
	}
	n.Attr = append(n.Attr, astro.Attribute{
		Key:  "style",
		Type: astro.ExpressionAttribute,
		Val:  definedVars,
	})
}

const startRunningService = async (): Promise<Service> => {
	const go = new Go();
	const wasm = await instantiateWASM(
		fileURLToPath(new URL('../astro.wasm', import.meta.url)),
		go.importObject
	);
	go.run(wasm.instance);
	const _service: any = (globalThis as any)['@astrojs/compiler'];
	return {
		transform: (input, options) =>
			new Promise((resolve) => {
				try {
					resolve(_service.transform(input, options || {}));
				} catch (err) {
					// Recreate the service next time on panic
					longLivedService = void 0;
					throw err;
				}
			}),
		parse: (input, options) =>
			new Promise((resolve) => resolve(_service.parse(input, options || {})))
				.catch((error) => {
					longLivedService = void 0;
					throw error;
				})
				.then((result: any) => ({ ...result, ast: JSON.parse(result.ast) })),
		convertToTSX: (input, options) => {
			return new Promise((resolve) => resolve(_service.convertToTSX(input, options || {})))
				.catch((error) => {
					longLivedService = void 0;
					throw error;
				})
				.then((result: any) => {
					return { ...result, map: JSON.parse(result.map) };
				});
		},
	};
};

