async ({ url, locals }) => {
	const { emdash, user } = locals;

	if (!emdash?.db) {
		return apiError("NOT_CONFIGURED", "EmDash is not initialized", 500);
	}

	const denied = requirePerm(user, "bylines:read");
	if (denied) return denied;

	const query = parseQuery(url, bylinesListQuery);
	if (isParseError(query)) return query;

	const i18n = getI18nConfig();
	if (query.locale && i18n && !i18n.locales.includes(query.locale)) {
		return apiError(
			"VALIDATION_ERROR",
			`Locale "${query.locale}" is not configured for this site`,
			400,
		);
	}

	try {
		const repo = new BylineRepository(emdash.db);
		const result = await repo.findMany({
			search: query.search,
			isGuest: query.isGuest,
			userId: query.userId,
			locale: query.locale,
			cursor: query.cursor,
			limit: query.limit,
		});

		return apiSuccess(result);
	} catch (error) {
		return handleError(error, "Failed to list bylines", "BYLINE_LIST_ERROR");
	}
}

async function resolveItem(item: SidebarItem, docs: DocsEntry[]): Promise<Link[]> {
	// Shorthand: a string is a slug reference.
	if (typeof item === "string") {
		const entry = getEntry("docs", item);
		return entry ? [entryLink(entry)] : [];
	}

	if ("link" in item && item.link) {
		return [{ label: item.label, href: item.link }];
	}

	if ("slug" in item && item.slug) {
		const entry = await getEntry("docs", item.slug);
		return entry ? [entryLink(entry, item.label)] : [];
	}

	if ("items" in item && item.items) {
		const out: Link[] = [];
		for (const child of item.items) {
			out.push(...(await resolveItem(child, docs)));
		}
		return out;
	}

	if ("autogenerate" in item && item.autogenerate) {
		const prefix = item.autogenerate.directory.replace(TRIM_SLASHES, "") + "/";
		return docs
			.filter((entry) => entry.id.startsWith(prefix))
			.toSorted((a, b) => a.id.localeCompare(b.id))
			.map((entry) => entryLink(entry));
	}

	return [];
}

async function generateIconTypeDefinitions(
  collections: IconCollection[],
  rootDir: URL,
  defaultPack = "local",
): Promise<void> {
  const typeFile = new URL("./.astro/icon.d.ts", rootDir);
  await ensureDir(new URL("./", typeFile));
  const oldHash = await tryGetHash(typeFile);
  const currentHash = collectionsHash(collections);
  if (currentHash === oldHash) {
    return;
  }
  await writeFile(
    typeFile,
    `// Automatically generated by astro-icon
// ${currentHash}

declare module 'virtual:astro-icon' {
\texport type Icon = ${
      collections.length > 0
        ? collections
            .map((collection) =>
              Object.keys(collection.icons)
                .concat(Object.keys(collection.aliases ?? {}))
                .map(
                  (icon) =>
                    `\n\t\t| "${
                      collection.prefix === defaultPack
                        ? ""
                        : `${collection.prefix}:`
                    }${icon}"`,
                ),
            )
            .flat(1)
            .join("")
        : "never"
    };
}`,
  );
}

