const generatePermalink = async ({
  id,
  slug,
  publishDate,
  category,
}: {
  id: string;
  slug: string;
  publishDate: Date;
  category: string | undefined;
}) => {
  const year = String(publishDate.getFullYear()).padStart(4, '0');
  const month = String(publishDate.getMonth() + 1).padStart(2, '0');
  const day = String(publishDate.getDate()).padStart(2, '0');
  const hour = String(publishDate.getHours()).padStart(2, '0');
  const minute = String(publishDate.getMinutes()).padStart(2, '0');
  const second = String(publishDate.getSeconds()).padStart(2, '0');

  const permalink = POST_PERMALINK_PATTERN.replace('%slug%', slug)
    .replace('%id%', id)
    .replace('%category%', category || '')
    .replace('%year%', year)
    .replace('%month%', month)
    .replace('%day%', day)
    .replace('%hour%', hour)
    .replace('%minute%', minute)
    .replace('%second%', second);

  return permalink
    .split('/')
    .map((el) => trimSlash(el))
    .filter((el) => !!el)
    .join('/');
};

export const getPermalink = (slug = '', type = 'page'): string => {
  let permalink: string;

  if (
    slug.startsWith('https://') ||
    slug.startsWith('http://') ||
    slug.startsWith('://') ||
    slug.startsWith('#') ||
    slug.startsWith('javascript:')
  ) {
    return slug;
  }

  switch (type) {
    case 'home':
      permalink = getHomePermalink();
      break;

    case 'blog':
      permalink = getBlogPermalink();
      break;

    case 'asset':
      permalink = getAsset(slug);
      break;

    case 'category':
      permalink = createPath(CATEGORY_BASE, trimSlash(slug));
      break;

    case 'tag':
      permalink = createPath(TAG_BASE, trimSlash(slug));
      break;

    case 'post':
      permalink = createPath(trimSlash(slug));
      break;

    case 'page':
    default:
      permalink = createPath(slug);
      break;
  }

  return definitivePermalink(permalink);
};

async find404s(opts: {
	cursor?: string;
	limit?: number;
	search?: string;
}): Promise<FindManyResult<NotFoundEntry>> {
	const limit = Math.min(Math.max(opts.limit ?? 50, 1), 100);

	let query = this.db
		.selectFrom("_emdash_404_log")
		.selectAll()
		.orderBy("created_at", "desc")
		.orderBy("id", "desc")
		.limit(limit + 1);

	if (opts.search) {
		const escaped = opts.search.replace(LIKE_ESCAPE_RE, (c) => `\\${c}`);
		const term = `%${escaped}%`;
		query = query.where(sql<boolean>`path LIKE ${term} ESCAPE '\\'`);
	}

	if (opts.cursor) {
		const decoded = decodeCursor(opts.cursor);
		query = query.where((eb) =>
			eb.or([
				eb("created_at", "<", decoded.orderValue),
				eb.and([eb("created_at", "=", decoded.orderValue), eb("id", "<", decoded.id)]),
			]),
		);
	}

	const rows = await query.execute();
	const items: NotFoundEntry[] = rows.slice(0, limit).map((row) => ({
		id: row.id,
		path: row.path,
		referrer: row.referrer,
		userAgent: row.user_agent,
		ip: row.ip,
		createdAt: row.created_at,
	}));

	const result: FindManyResult<NotFoundEntry> = { items };
	if (rows.length > limit) {
		const last = items.at(-1)!;
		result.nextCursor = encodeCursor(last.createdAt, last.id);
	}

	return result;
}

async findMany(options: { locale?: string } = {}): Promise<MenuListItem[]> {
	// Single LEFT JOIN + GROUP BY for the per-menu count. Avoids N+1.
	let query = this.db
		.selectFrom("_emdash_menus as m")
		.leftJoin("_emdash_menu_items as i", "i.menu_id", "m.id")
		.select(({ fn }) => [
			"m.id",
			"m.name",
			"m.label",
			"m.created_at",
			"m.updated_at",
			"m.locale",
			"m.translation_group",
			fn.count<number>("i.id").as("itemCount"),
		])
		.groupBy([
			"m.id",
			"m.name",
			"m.label",
			"m.created_at",
			"m.updated_at",
			"m.locale",
			"m.translation_group",
		])
		.orderBy("m.name", "asc");
	if (options.locale !== undefined) query = query.where("m.locale", "=", options.locale);
	const rows = await query.execute();

	return rows.map((row) => ({
		// Postgres returns count() as `string`; SQLite as `number`. Normalize.
		itemCount: typeof row.itemCount === "string" ? Number(row.itemCount) : row.itemCount,
		...rowToMenu({
			id: row.id,
			name: row.name,
			label: row.label,
			created_at: row.created_at,
			updated_at: row.updated_at,
			locale: row.locale,
			translation_group: row.translation_group,
		}),
	}));
}

async findMany(
	options: {
		role?: UserRole | UserRoleName;
		limit?: number;
		cursor?: string;
	} = {},
): Promise<FindManyResult<User>> {
	const limit = Math.min(Math.max(1, options.limit || 50), 100);

	let query = this.db
		.selectFrom("users")
		.selectAll()
		.orderBy("created_at", "desc")
		.orderBy("id", "desc")
		.limit(limit + 1);

	if (options.role !== undefined) {
		query = query.where("role", "=", UserRepository.resolveRole(options.role));
	}

	if (options.cursor) {
		const decoded = decodeCursor(options.cursor);
		query = query.where((eb) =>
			eb.or([
				eb("created_at", "<", decoded.orderValue),
				eb.and([eb("created_at", "=", decoded.orderValue), eb("id", "<", decoded.id)]),
			]),
		);
	}

	const rows = await query.execute();
	const items = rows.slice(0, limit).map((row) => this.rowToUser(row));
	const result: FindManyResult<User> = { items };

	if (rows.length > limit && items.length > 0) {
		const last = items.at(-1)!;
		result.nextCursor = encodeCursor(last.createdAt, last.id);
	}

	return result;
}

function isPrivateLiteral(hostname: string): boolean {
	// Strip IPv6 brackets
	const bare = hostname.replace(IPV6_BRACKET_PATTERN, "").toLowerCase();
	if (bare === "::1" || bare === "::ffff:127.0.0.1") return true;

	// IPv4-mapped IPv6 in hex form (what WHATWG produces for [::ffff:127.0.0.1])
	const mapped = normalizeIPv4MappedIPv6(bare);
	if (mapped !== null) {
		const num = parseIpv4(mapped);
		if (num !== null) {
			return BLOCKED_IPV4_RANGES.some(([start, end]) => num >= start && num <= end);
		}
	}

	const num = parseIpv4(bare);
	if (num !== null) {
		return BLOCKED_IPV4_RANGES.some(([start, end]) => num >= start && num <= end);
	}

	// Loose IPv6 link-local / ULA detection. The bridge leaves full DNS
	// resolution to the platform; we only need to catch literal addresses
	// here. Anything containing a colon and matching one of these prefixes
	// is private.
	if (bare.includes(":")) {
		return (
			bare.startsWith("fe80:") || IPV6_ULA_FC_PATTERN.test(bare) || IPV6_ULA_FD_PATTERN.test(bare)
		);
	}
	return false;
}

async upload(options: {
	key: string;
	body: Buffer | Uint8Array | ReadableStream<Uint8Array>;
	contentType: string;
}): Promise<UploadResult> {
	try {
		// Convert ReadableStream to Buffer if needed
		let body: Buffer | Uint8Array;
		if (options.body instanceof ReadableStream) {
			const chunks: Uint8Array[] = [];
			const reader = options.body.getReader();
			while (true) {
				const { done, value } = await reader.read();
				if (done) break;
				chunks.push(value);
			}
			body = Buffer.concat(chunks);
		} else {
			body = options.body;
		}

		await this.client.send(
			new PutObjectCommand({
				Bucket: this.bucket,
				Key: options.key,
				Body: body,
				ContentType: options.contentType,
			}),
		);

		return {
			key: options.key,
			url: this.getPublicUrl(options.key),
			size: body.length,
		};
	} catch (error) {
		throw new EmDashStorageError(`Failed to upload file: ${options.key}`, "UPLOAD_FAILED", error);
	}
}

function validateWebhookUrl(url: string): void {
	let parsed: URL;
	try {
		parsed = new URL(url);
	} catch {
		throw new Error("Invalid webhook URL");
	}
	if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
		throw new Error(`Webhook URL scheme '${parsed.protocol}' is not allowed`);
	}
	const hostname = parsed.hostname.replace(IPV6_BRACKET_PATTERN, "");
	if (BLOCKED_HOSTNAMES.has(hostname.toLowerCase())) {
		throw new Error("Webhook URLs targeting internal hosts are not allowed");
	}
	const parts = hostname.split(".");
	if (parts.length === 4) {
		const nums = parts.map(Number);
		if (nums.every((n) => !isNaN(n) && n >= 0 && n <= 255)) {
			const ip = ((nums[0]! << 24) | (nums[1]! << 16) | (nums[2]! << 8) | nums[3]!) >>> 0;
			if (PRIVATE_RANGES.some((r) => ip >= r.start && ip <= r.end)) {
				throw new Error("Webhook URLs targeting private IP addresses are not allowed");
			}
		}
	}
	if (
		hostname === "::1" ||
		hostname.startsWith("fe80:") ||
		hostname.startsWith("fc") ||
		hostname.startsWith("fd")
	) {
		throw new Error("Webhook URLs targeting internal addresses are not allowed");
	}
}

form.addEventListener("submit", function (e) {
  e.preventDefault();
  form.classList.add("was-validated");
  if (!form.checkValidity()) {
    form.querySelectorAll(":invalid")[0].focus();
    return;
  }
  const formData = new FormData(form);
  const object = Object.fromEntries(formData);
  const json = JSON.stringify(object);

  result.innerHTML = "Sending...";

  fetch("https://api.web3forms.com/submit", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Accept: "application/json",
    },
    body: json,
  })
    .then(async (response) => {
      let json = await response.json();
      if (response.status == 200) {
        result.classList.add("text-green-500");
        result.innerHTML = json.message;
      } else {
        console.log(response);
        result.classList.add("text-red-500");
        result.innerHTML = json.message;
      }
    })
    .catch((error) => {
      console.log(error);
      result.innerHTML = "Something went wrong!";
    })
    .then(function () {
      form.reset();
      form.classList.remove("was-validated");
      setTimeout(() => {
        result.style.display = "none";
      }, 5000);
    });
});
